const itemsOut = [];

for (const item of items) {
  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {
    itemsOut.push({
      json: item.json,
      binary: {
        data: item.binary[key]   // <-- padrão do Google Drive node
      }
    });
  }
}

return itemsOut;

return [
  {
    json: {
      statusCode: 409,
      message: "CPF já cadastrado"
    }
  }
];

return [
  {
    json: {
      statusCode: 200,
        message: "Cadastro realizado com sucesso",
        token: $input.first().json.id,
        user: {
          id: $('Insere no users').first().json.id,
          nome: $('Insere no users').first().json.fullname,
          cpf: $('Insere no users').first().json.cpf,
          email: $('Insere no users').first().json.email
        }

    }
  }
]

