INSERT INTO users (fullname, email, google_sub, role, is_active)
VALUES ('{{ $('HTTP Request').item.json.name }}', '{{ $('HTTP Request').item.json.email }}', '{{ $('HTTP Request').item.json.sub }}', 'client', true)
RETURNING *;

